	if (gpu.name.includes("H200")) baseTps = 90;
	if (gpu.name.includes("B200") || gpu.name.includes("GB200")) baseTps = 120;
	if (gpu.name.includes("M2 Ultra") || gpu.name.includes("M4 Max")) baseTps = 35;
