	if (bytesPerParam <= .5) estimatedTps *= 1.8;
	else if (bytesPerParam <= 1) estimatedTps *= 1.4;
	if (gpusNeeded > 1) estimatedTps *= .8;
	if (gpusNeeded > 4) estimatedTps *= .7;
	if (gpu.category === "Laptop") estimatedTps *= .7;
